#include <bits/stdc++.h>
using namespace std;
int a[22][22];
int main(){
    int n;
    cin>>n;
    int x=n/2+n%2,y=1;
    for(int i=1;i<=n*n;i++){
        a[y][x]=i;
        y--;
        if(y==0){
            y=n;
        }
        x++;
        if(x==n+1){
            x=1;
        }
        if(a[y][x]!=0){
            x--;
            if(x==0){
				x=n;
			}
			y++;
			if(y==n+1){
				y=1;
			}
			y++;
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            cout<<a[i][j]<<" ";
        }
        cout<<endl;
    }
    return 0;
}
